top_k_by_metric.cte_template:
WITH ranked_items AS (
  SELECT 
    {group_by_column},
    COUNT(*) as execution_count,
    {metric_formula} as metric_value,
    ROW_NUMBER() OVER (ORDER BY {metric_formula} {order_direction}) as rank
  FROM {table_name}
  WHERE {filter_conditions}
  GROUP BY {group_by_column}
  HAVING COUNT(*) > {min_count}
)
SELECT * FROM ranked_items WHERE rank <= {k}

comparison_period.cte_template:
WITH current_period AS (
  SELECT 
    {group_by_column},
    COUNT(*) as count,
    {metric_formula} as metric_value
  FROM {table_name}
  WHERE start_time >= {current_period_start}
    AND start_time < {current_period_end}
    {additional_filters}
  GROUP BY {group_by_column}
),
previous_period AS (
  SELECT 
    {group_by_column},
    COUNT(*) as count,
    {metric_formula} as metric_value
  FROM {table_name}
  WHERE start_time >= {previous_period_start}
    AND start_time < {previous_period_end}
    {additional_filters}
  GROUP BY {group_by_column}
)
SELECT 
  COALESCE(c.{group_by_column}, p.{group_by_column}) as {group_by_column},
  p.count as previous_count,
  c.count as current_count,
  p.metric_value as previous_metric,
  c.metric_value as current_metric,
  ROUND((c.metric_value - p.metric_value)::numeric, 2) as metric_change,
  ROUND((100.0 * (c.metric_value - p.metric_value) / NULLIF(p.metric_value, 0))::numeric, 2) as metric_change_pct
FROM current_period c
FULL OUTER JOIN previous_period p ON c.{group_by_column} = p.{group_by_column}
ORDER BY ABS(metric_change_pct) DESC NULLS LAST

multi_table_join.cte_template:
WITH process_metrics AS (
  SELECT 
    id,
    proc_def_id,
    EXTRACT(EPOCH FROM (end_time - start_time)) as duration_seconds,
    status
  FROM pe_ext_procinst
  WHERE {filter_conditions}
),
aggregated_metrics AS (
  SELECT 
    {group_by_column},
    COUNT(*) as process_count,
    ROUND((AVG(duration_seconds))::numeric, 2) as avg_duration,
    {additional_metrics}
  FROM process_metrics
  {join_clause}
  GROUP BY {group_by_column}
)
SELECT * FROM aggregated_metrics
ORDER BY {order_by_clause}
